import{_ as e,o as i,c as o,ai as a}from"./chunks/framework.CaiDwmc7.js";const p=JSON.parse('{"title":"物联网项目学习路线（面向中小企业场景）","description":"","frontmatter":{},"headers":[],"relativePath":"tech-system/backend/iot-project.md","filePath":"tech-system/backend/iot-project.md"}'),t={name:"tech-system/backend/iot-project.md"};function r(n,l,s,c,d,u){return i(),o("div",null,[...l[0]||(l[0]=[a('<h1 id="物联网项目学习路线-面向中小企业场景" tabindex="-1">物联网项目学习路线（面向中小企业场景） <a class="header-anchor" href="#物联网项目学习路线-面向中小企业场景" aria-label="Permalink to “物联网项目学习路线（面向中小企业场景）”">​</a></h1><blockquote><p>结合你自己的经历（智能垃圾桶、远程设备监控、小程序后台等），这里给一个<strong>偏实战、可落地</strong>的物联网项目学习路线，主打：<strong>Java 后端 + Web 管理端 + 小程序/前端展示</strong>。</p></blockquote><hr><h2 id="一、整体目标-从-能看懂-到-能独立搭一套" tabindex="-1">一、整体目标：从“能看懂”到“能独立搭一套” <a class="header-anchor" href="#一、整体目标-从-能看懂-到-能独立搭一套" aria-label="Permalink to “一、整体目标：从“能看懂”到“能独立搭一套””">​</a></h2><p>学习这部分，主要想达成两个目标：</p><ol><li><strong>能听懂/看懂常见 IoT 项目架构</strong><ul><li>设备端、大量数据上报、MQ/缓存、数据库、告警、可视化这些组件如何协作。</li></ul></li><li><strong>能独立实现一个简化版的物联网平台</strong><ul><li>支持设备注册/绑定、心跳上报、数据查看、简单告警、小程序/前端展示。</li></ul></li></ol><hr><h2 id="二、基础知识补齐-1-2-周" tabindex="-1">二、基础知识补齐（1～2 周） <a class="header-anchor" href="#二、基础知识补齐-1-2-周" aria-label="Permalink to “二、基础知识补齐（1～2 周）”">​</a></h2><blockquote><p>目标：先懂“物联网和普通 Web 项目到底多了什么/不一样什么”，再上手项目。</p></blockquote><ul><li><p><strong>1. 通信协议与连接方式</strong></p><ul><li>HTTP / WebSocket：适合 Web 管理端 &amp; 简单设备上报。</li><li>MQTT：高并发、小数据量上报常用协议（QoS、主题、客户端 ID 等概念）。</li><li>你可以先用 HTTP / WebSocket 入门，理解流程后再了解 MQTT。</li><li><strong>补充（跨服务 / 工控）</strong>：跨语言调用方式总览见 <a href="/tech-system/integration/cross-language-interop.html">跨语言调用（选型）</a>；Node 与 Python 用 HTTP 协作、Node 读 PLC（Modbus TCP）见 <a href="/tech-system/integration/http-node-python.html">HTTP 协作</a> 与 <a href="/tech-system/integration/modbus-tcp-node-plc.html">Modbus TCP</a>。</li></ul></li><li><p><strong>2. 设备与平台的基本概念</strong></p><ul><li>设备（Device） vs 设备类型（Device Type / Product）。</li><li>设备属性（属性上报/设置）、事件（Event）、遥测数据（Telemetry）。</li><li>设备状态：在线/离线、心跳、最后上报时间。</li></ul></li><li><p><strong>3. 常见组件</strong></p><ul><li>消息中间件：如 RabbitMQ / Kafka，用于解耦设备上报与后端处理。</li><li>缓存：用 Redis 存储设备在线状态、最新数据快照。</li><li>数据库：MySQL 存结构化数据（设备、用户、规则），时序数据可先存在普通表里。</li></ul></li></ul><blockquote><p>建议：可以简单浏览 <code>open-source/iot.md</code> 中推荐的开源项目（如 ThingsBoard），看一眼他们的架构图和模块划分。</p></blockquote><hr><h2 id="三、核心项目骨架设计-1-2-周" tabindex="-1">三、核心项目骨架设计（1～2 周） <a class="header-anchor" href="#三、核心项目骨架设计-1-2-周" aria-label="Permalink to “三、核心项目骨架设计（1～2 周）”">​</a></h2><blockquote><p>这里以你熟悉的 <strong>Java + Spring Boot + Vue/小程序</strong> 为例，设计一个“简化版物联网云平台”。</p></blockquote><h3 id="_3-1-后端服务模块划分" tabindex="-1">3.1 后端服务模块划分 <a class="header-anchor" href="#_3-1-后端服务模块划分" aria-label="Permalink to “3.1 后端服务模块划分”">​</a></h3><ul><li><p><strong>设备接入模块</strong></p><ul><li>提供 HTTP / WebSocket 接口，模拟设备上报数据： <ul><li>设备注册：<code>/api/device/register</code></li><li>心跳上报：<code>/api/device/heartbeat</code></li><li>数据上报：<code>/api/device/telemetry</code></li></ul></li><li>设备认证：简单可以用 <code>deviceId + secret</code> 形式。</li></ul></li><li><p><strong>设备管理模块</strong></p><ul><li>设备 CRUD：添加设备、批量导入、启用/停用。</li><li>设备分组：按项目、小区、楼栋、区域等分组。</li><li>设备状态：统计在线/离线数量、最近上报时间。</li></ul></li><li><p><strong>数据存储与查询模块</strong></p><ul><li>结构化表：设备表、设备类型表、用户表。</li><li>数据表：设备数据表（如：<code>device_telemetry</code>，字段包含 <code>device_id</code>、<code>metric</code>、<code>value</code>、<code>timestamp</code>）。</li><li>查询 API：按设备、时间范围查询数据，返回给前端图表展示。</li></ul></li><li><p><strong>告警与规则模块（入门版可选）</strong></p><ul><li>简单规则：如“垃圾桶满载 &gt; 90% 触发告警”。</li><li>告警记录：记录告警时间、原因、处理状态。</li></ul></li></ul><h3 id="_3-2-前端-小程序功能规划" tabindex="-1">3.2 前端 / 小程序功能规划 <a class="header-anchor" href="#_3-2-前端-小程序功能规划" aria-label="Permalink to “3.2 前端 / 小程序功能规划”">​</a></h3><ul><li><p><strong>平台管理端（Web / Vue）</strong></p><ul><li>设备列表页：查看设备状态、最后上报时间。</li><li>设备详情页：折线图展示某一设备的历史数据（如容量、温度、电量）。</li><li>告警列表页：显示未处理告警。</li></ul></li><li><p><strong>简单展示端（小程序 / H5）</strong></p><ul><li>展示某个区域的设备运行状态总览。</li><li>查看附近设备的状态（结合地理位置可选）。</li></ul></li></ul><hr><h2 id="四、分阶段实现建议" tabindex="-1">四、分阶段实现建议 <a class="header-anchor" href="#四、分阶段实现建议" aria-label="Permalink to “四、分阶段实现建议”">​</a></h2><blockquote><p>不要求一次性做完，而是拆成“每一阶段都能跑”的小目标，方便你写到简历/面试里。</p></blockquote><h3 id="阶段-1-最小可用-demo-1-周" tabindex="-1">阶段 1：最小可用 Demo（1 周） <a class="header-anchor" href="#阶段-1-最小可用-demo-1-周" aria-label="Permalink to “阶段 1：最小可用 Demo（1 周）”">​</a></h3><ul><li>后端： <ul><li>用 Spring Boot 建一个最小项目： <ul><li><code>/api/device/register</code>：写入设备表。</li><li><code>/api/device/telemetry</code>：把上报的数据写入 <code>device_telemetry</code> 表。</li></ul></li><li>使用 Postman / 脚本模拟设备上报。</li></ul></li><li>前端： <ul><li>一个简单页面展示设备列表 + 最近一条数据。</li></ul></li></ul><p><strong>面试可讲亮点：</strong><br> “支持设备注册和数据上报，能在后台看到每个设备最近一次上报的数据和时间。”</p><h3 id="阶段-2-状态-可视化-1-2-周" tabindex="-1">阶段 2：状态 &amp; 可视化（1～2 周） <a class="header-anchor" href="#阶段-2-状态-可视化-1-2-周" aria-label="Permalink to “阶段 2：状态 &amp; 可视化（1～2 周）”">​</a></h3><ul><li>增强点： <ul><li>使用 Redis 记录设备在线状态（心跳超时时间判断在线/离线）。</li><li>提供接口返回某段时间的历史数据，用前端折线图展示。</li><li>增加简单告警规则（如数值阈值超限）。</li></ul></li></ul><p><strong>面试可讲亮点：</strong><br> “通过心跳 + Redis 维护设备在线状态，并用折线图展示设备的历史指标曲线，支持简单阈值告警。”</p><h3 id="阶段-3-项目包装与拓展-按需" tabindex="-1">阶段 3：项目包装与拓展（按需） <a class="header-anchor" href="#阶段-3-项目包装与拓展-按需" aria-label="Permalink to “阶段 3：项目包装与拓展（按需）”">​</a></h3><ul><li>拓展方向： <ul><li>权限与多租户：不同客户看到自己的设备。</li><li>任务调度：定时检查离线设备、发送告警。</li><li>与已有系统集成：比如将数据推送到现有 CRM/运维平台。</li></ul></li></ul><p><strong>面试可讲亮点：</strong><br> “在原有 CRUD 业务基础上，引入了设备在线状态、告警、时序数据查询等物联网特性，并预留了多租户和扩展能力。”</p><hr><h2 id="五、如何和你现有技术栈结合复习" tabindex="-1">五、如何和你现有技术栈结合复习 <a class="header-anchor" href="#五、如何和你现有技术栈结合复习" aria-label="Permalink to “五、如何和你现有技术栈结合复习”">​</a></h2><ul><li><strong>Java / Spring Boot：</strong><ul><li>Controller/Service/Repository 分层设计。</li><li>定时任务（检查离线设备、清理历史数据）。</li></ul></li><li><strong>数据库 / MySQL：</strong><ul><li>设备数据表的索引设计（按 <code>device_id + 时间</code> 建联合索引）。</li><li>历史数据归档策略（按月/按设备拆表可作为进阶思考）。</li></ul></li><li><strong>Redis：</strong><ul><li>在线状态缓存：<code>key = device:online:{deviceId}</code>，value 存最后心跳时间。</li><li>简单的限流/防刷策略（可选）。</li></ul></li><li><strong>前端 / Vue / 小程序：</strong><ul><li>列表 + 图表展示。</li><li>与后端的接口约定与鉴权。</li></ul></li></ul><hr><h2 id="六、下一步可以做的事" tabindex="-1">六、下一步可以做的事 <a class="header-anchor" href="#六、下一步可以做的事" aria-label="Permalink to “六、下一步可以做的事”">​</a></h2><ul><li>在 <code>open-source/iot.md</code> 中选一个项目（如 ThingsBoard），参考它的模块划分，和你自己的简化版对比。</li><li>在简历和面试话术中，把这个物联网项目作为<strong>重点项目</strong>来讲： <ul><li>强调：设备接入、数据上报、在线状态、告警、可视化，而不仅仅是 CRUD。</li></ul></li></ul>',36)])])}const g=e(t,[["render",r]]);export{p as __pageData,g as default};
